<?php
namespace Tests\Feature;use App\Models\Employee;use App\Models\Role;use App\Models\User;use Illuminate\Foundation\Testing\RefreshDatabase;use Laravel\Sanctum\Sanctum;use Tests\TestCase;
class SelfServiceTest extends TestCase{use RefreshDatabase;public function test_check_in_uses_authenticated_employee_and_rejects_duplicate():void{$role=Role::create(['name'=>'Employee','slug'=>'employee','permissions'=>['attendance.self'],'is_active'=>true]);$user=User::factory()->create(['role_id'=>$role->id,'is_active'=>true]);$own=Employee::create(['user_id'=>$user->id,'joining_date'=>now(),'employment_type'=>'full-time','salary'=>0]);$otherUser=User::factory()->create(['role_id'=>$role->id,'is_active'=>true]);$other=Employee::create(['user_id'=>$otherUser->id,'joining_date'=>now(),'employment_type'=>'full-time','salary'=>0]);Sanctum::actingAs($user);$this->postJson('/api/attendances/my-checkin',['employee_id'=>$other->id])->assertOk();$this->assertDatabaseHas('attendances',['employee_id'=>$own->id,'date'=>today()->toDateString()]);$this->assertDatabaseMissing('attendances',['employee_id'=>$other->id]);$this->postJson('/api/attendances/my-checkin')->assertUnprocessable();$this->getJson('/api/self-service/overview')->assertOk()->assertJsonPath('profile.id',$own->id);}}
